"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["3178"],{30009(e,o,s){s.r(o),s.d(o,{default:()=>r});var a=s(74848),n=s(47643),i=JSON.parse('{"id":201,"es":{"title":"Generador de documentaci\xf3n de procesos","prompt":"You will act as a process document generator. Below, I will briefly describe what a process document is so that you can play it better. Generally speaking, a process document contains about 10 major items, and there are several sub-items under the major items. Of course, not all major items contain sub-items. The 10 major items generally include [1. Process Overview2. Objectives3. Scope of application4. Process Owner5. Definition and Terminology6. Related Process Standards (Process Interface)7. Organizational Responsibilities8. System and Operating Permissions9. Business Process Flowchart10. Process Description.] I Hopefully you only output the content of the process document and nothing else. Respond in Spanish. My first process document was [tema].","description":"Usted desempe\xf1ar\xe1 el papel de generador de documentaci\xf3n de procesos. A continuaci\xf3n, describir\xe9 brevemente qu\xe9 es un documento de proceso para que pueda ejecutarlo mejor. Normalmente, un documento de proceso consta de unos 10 elementos principales, con varios subelementos bajo los elementos principales. Por supuesto, no todos los grandes proyectos contienen subproyectos. Los 10 puntos principales suelen incluir [1. visi\xf3n general del proceso 2. objetivos 3. \xe1mbito de aplicaci\xf3n 4. responsables del proceso 5. definiciones y terminolog\xeda 6. normas de proceso relevantes (interfaces de proceso) 7. responsabilidades organizativas 8. privilegios operativos y del sistema 9. diagramas de proceso de negocio 10. descripciones del proceso]. Espero que s\xf3lo emita el contenido del documento de proceso y nada m\xe1s. Por favor, responda en chino.","remark":"Generar esquemas para documentos de flujo fijo, tambi\xe9n se utiliza para otros tipos de documentos. Contribuci\xf3n de @junkdo."},"tags":["contribute","tool"],"website":null,"count":737,"related":[{"id":220,"title":"Planificaci\xf3n de rutas de viaje","remark":"Planificaci\xf3n aproximada en funci\xf3n del destino del viaje, el presupuesto, el tiempo y las necesidades. Contribuci\xf3n de @suaifu."},{"id":267,"title":"Reducci\xf3n del peso de la disertaci\xf3n","remark":"Contribuci\xf3n de @SkinnyEggsLeanMeatWeek."},{"id":245,"title":"Dise\xf1o de iconos","remark":"Traducir un concepto o una idea en algo concreto hace que la idea de dise\xf1o sea tangible. Compartido por @Liang Zhehao."}],"metaTitle":"Generador Docs Procesos","metaDescription":"\xbfDocumentaci\xf3n? Genere docs de procesos est\xe1ndar (10 \xedtems). Objetivos, alcance, flujos y descripci\xf3n. \xa1Mejora tu flujo!","faq":[{"q":"\xbfSirve para procesos no fijos (proyectos creativos)?","a":"Poco. Est\xe1 estructurado en \xab10 bloques con sub\xedtems\xbb; proyectos creativos saltan entre fases y esa plantilla los hace r\xedgidos. Para procesos fijos (facturaci\xf3n, onboarding, reembolsos) es ideal; para documentos creativos usa el ID 214 (informe de investigaci\xf3n) o el ID 187 (PPT)."},{"q":"\xbfSuele omitir pasos clave?","a":"S\xed. Tiende a olvidar manejo de excepciones, rutas de vuelta atr\xe1s y responsables. Con el primer borrador, camina t\xfa por el flujo preguntando \xab\xbfqu\xe9 pasa si este paso falla?\xbb, \xab\xbfqui\xe9n aprueba?\xbb, \xab\xbfcu\xe1nto toma esta decisi\xf3n?\xbb y a\xf1ade los puntos ciegos."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function r(){return(0,a.jsx)(n.A,{prompt:i,currentLanguage:"es"})}}}]);